-- Table structure for progress_logs
-- ----------------------------
DROP TABLE IF EXISTS `progress_logs`;
CREATE TABLE `progress_logs`  (
  `log_id` int NOT NULL AUTO_INCREMENT,
  `task_id` int NOT NULL COMMENT 'อ้างอิงงานจากตาราง tasks',
  `log_date` date NOT NULL COMMENT 'วันที่บันทึกความคืบหน้า',
  `actual_progress` decimal(5, 2) NOT NULL COMMENT '% ความคืบหน้าจริง (0-100)',
