-- ----------------------------
-- Table structure for progress_summaries
-- ----------------------------
DROP TABLE IF EXISTS `progress_summaries`;
CREATE TABLE `progress_summaries`  (
  `summary_id` int NOT NULL AUTO_INCREMENT COMMENT 'รหัสสรุปความคืบหน้า',
  `project_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `installment` int NOT NULL DEFAULT 1 COMMENT 'งวดที่',
  `summary_date` date NOT NULL COMMENT 'วันที่สรุปความคืบหน้า',
  `planned_progress` decimal(5, 2) NOT NULL COMMENT 'ผลงานตามแผน (%) - กรอกเอง',
  `actual_progress` decimal(5, 2) NOT NULL COMMENT 'ผลงานที่ทำได้จริง (%) - กรอกเอง',
  `progress_ahead` decimal(5, 2) NULL DEFAULT 0.00 COMMENT 'ผลงานเร็วกว่าแผน (%) - กรอกเอง',
  `progress_behind` decimal(5, 2) NULL DEFAULT 0.00 COMMENT 'งานล่าช้ากว่าแผน (%) - กรอกเอง',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'หมายเหตุ/รายละเอียดเพิ่มเติม',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'วันที่สร้างรายการ',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'วันที่แก้ไขล่าสุด',
  `created_by` int NULL DEFAULT NULL COMMENT 'ผู้สร้างรายการ (user_id)',
  PRIMARY KEY (`summary_id`) USING BTREE,
  UNIQUE INDEX `unique_project_installment`(`project_id` ASC, `installment` ASC) USING BTREE,
  INDEX `idx_progress_summaries_summary_date`(`summary_date` ASC) USING BTREE,
  CONSTRAINT `fk_progress_summaries_project` FOREIGN KEY (`project_id`) REFERENCES `projects` (`project_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'ตารางสรุปความคืบหน้าโครงการ (กรอกข้อมูลเองทั้งหมด)' ROW_FORMAT = DYNAMIC;

