  `status` enum('Planning','In Progress','Completed') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'Planning' COMMENT 'สถานะงาน',
  `progress` int NULL DEFAULT 0 COMMENT 'ความคืบหน้า (%) สำหรับอัปเดตกราฟ',
  `active` tinyint(1) NOT NULL DEFAULT 1,
