-- ----------------------------
-- Table structure for tasks
-- ----------------------------
DROP TABLE IF EXISTS `tasks`;
CREATE TABLE `tasks`  (
  `task_id` int NOT NULL AUTO_INCREMENT,
  `project_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `parent_id` int NULL DEFAULT NULL COMMENT 'อ้างอิง task_id ของงานแม่ (NULL ถ้าเป็นงานหลัก)',
  `item_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'รหัส item เช่น 1, 01, 02',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'รายละเอียดงาน เช่น เจาะพื้นคอนกรีต',
  `amount` decimal(15, 2) NOT NULL COMMENT 'มูลค่างาน (Baht)',
  `weight` decimal(5, 4) NOT NULL COMMENT 'สัดส่วนน้ำหนัก (เช่น 0.0405)',
  `duration` int NOT NULL COMMENT 'ระยะเวลา (Days)',
  `start_date` date NOT NULL COMMENT 'วันที่เริ่มงาน',
  `end_date` date NOT NULL COMMENT 'วันที่สิ้นสุดงาน',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`task_id`) USING BTREE,
  INDEX `parent_id`(`parent_id` ASC) USING BTREE,
  INDEX `fk_tasks_project`(`project_id` ASC) USING BTREE,
  CONSTRAINT `fk_tasks_project` FOREIGN KEY (`project_id`) REFERENCES `projects` (`project_id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `tasks_ibfk_2` FOREIGN KEY (`parent_id`) REFERENCES `tasks` (`task_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

