-- ----------------------------
-- View structure for payment_installments_view
-- ----------------------------
DROP VIEW IF EXISTS `payment_installments_view`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `payment_installments_view` AS select `pi`.`installment_id` AS `installment_id`,`pi`.`payment_id` AS `payment_id`,`pi`.`project_id` AS `project_id`,`pi`.`installment_number` AS `installment_number`,`pi`.`amount` AS `amount`,`pi`.`payment_date` AS `payment_date`,ifnull(((`pi`.`amount` / `p`.`total_amount`) * 100),0) AS `percentage`,`pi`.`created_at` AS `created_at`,`pi`.`updated_at` AS `updated_at` from (`payment_installments` `pi` join `payments` `p` on((`pi`.`payment_id` = `p`.`payment_id`)));

SET FOREIGN_KEY_CHECKS = 1;
